def test_tc_gw_c04_001_msg_counter_present(can_bus):
    msgs = collect_messages(can_bus, 0x119, 3)
    for msg in msgs:
        assert decode_msg_counter(msg) is not None

def test_tc_gw_c04_002_counter_increments(can_bus):
    msgs = collect_messages(can_bus, 0x119, 5)
    counters = [decode_msg_counter(m) for m in msgs]
    for i in range(1, len(counters)):
        assert counters[i] == (counters[i - 1] + 1) % 16

def test_tc_gw_c04_004_no_skipped_values(can_bus):
    msgs = collect_messages(can_bus, 0x119, 10)
    counters = [decode_msg_counter(m) for m in msgs]
    for i in range(1, len(counters)):
