def test_tc_gw_c04_006_counter_after_ignition_cycle(can_bus):
    time.sleep(3)
    msgs = collect_messages(can_bus, 0x119, 3)
    counters = [decode_msg_counter(m) for m in msgs]
    for i in range(1, len(counters)):
        assert counters[i] == (counters[i - 1] + 1) % 16

def test_tc_gw_c04_007_counter_range(can_bus):
    msgs = collect_messages(can_bus, 0x119, 10)
    for msg in msgs:
        assert 0 <= decode_msg_counter(msg) <= 15

